func:
// Valideer
if (!msg.payload.order_nr) {
    msg.statusCode = 400;
    msg.payload = { error: "order_nr is verplicht" };
    return [null, msg];
}

// Bewaar input voordat we payload overschrijven
var input = msg.payload;

// Bouw UMH Core API payload
msg.url = "http://umh-core:8090/api/v1/";
msg.headers = { "Content-Type": "application/json" };
msg.payload = {
    event_type: "order.created",
    line_id: input.asset || "production",
    data: {
        id: input.order_nr,
        product_id: input.product || "onbekend",
        planned_qty: input.qty || 1,
        customer: input.customer || null,
        priority: input.priority || null,
        due_date: input.due_date || null
    }
};

return [msg, null];

msg.statusCode = 200;
msg.payload = {
    status: "ok",
    message: "Werkorder gepubliceerd naar UMH UNS"
};
return msg;
